choose.when:
SELECT EM.ENTRPRS_MBER_ID AS userId, EM.CMPNY_NM AS name, EM.ENTRPRS_MBER_PASSWORD AS userPw, EM.BIZRNO AS ihidNum, EM.APPLCNT_EMAIL_ADRES AS email, 'ENT' AS userSe, '' AS orgnztId, EM.ESNTL_ID AS uniqId, '' AS ip, ES.AUTHOR_CODE AS authorCode, EM.AUTH_TY AS authTy, EM.AUTH_DN AS authDn, EM.AUTH_CI AS authCi, EM.AUTH_DI AS authDi, EM.ENTRPRS_MBER_STTUS AS memberStatus FROM COMTNENTRPRSMBER EM INNER JOIN COMTNEMPLYRSCRTYESTBS ES ON EM.ESNTL_ID = ES.SCRTY_DTRMN_TRGET_ID WHERE EM.ENTRPRS_MBER_ID = #{userId}
AND EM.PROJECT_ID = #{projectId}
AND EM.ENTRPRS_MBER_STTUS IN ('A', 'P', 'R')

